import React, { useState, useEffect, useRef } from 'react';
import { apiFetch } from '../api';
import './css/GroceryList.css';

const DAY_NAMES = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
const MONTH_NAMES = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];

function startOfWeek(date) {
  const d = new Date(date);
  d.setDate(d.getDate() - d.getDay());
  d.setHours(0,0,0,0);
  return d;
}
function addDays(date, n) {
  const d = new Date(date); d.setDate(d.getDate() + n); return d;
}
function formatDate(date) {
  return new Date(date).toISOString().split('T')[0];
}

const CATEGORIES = {
  produce:   { label: 'Produce',    icon: '🥦', keywords: ['apple','banana','orange','lemon','lime','tomato','tomatoes','lettuce','spinach','kale','arugula','onion','onions','garlic','shallot','carrot','carrots','celery','cucumber','zucchini','pepper','peppers','potato','potatoes','broccoli','cauliflower','mushroom','mushrooms','avocado','corn','pea','peas','bean','beans','ginger','cilantro','parsley','basil','thyme','rosemary','mint','dill','chive','chives','scallion','scallions','leek','leeks','fennel','radish','beet','beets','squash','pumpkin','eggplant','asparagus','artichoke','cabbage','bok choy','brussels','sprouts','mango','pineapple','strawberry','blueberry','raspberry','blackberry','grape','grapes','cherry','cherries','peach','plum','pear','watermelon','melon','fig','date','pomegranate'] },
  dairy:     { label: 'Dairy & Eggs', icon: '🥛', keywords: ['milk','cream','butter','cheese','parmesan','mozzarella','cheddar','feta','ricotta','brie','gouda','yogurt','sour cream','half and half','heavy cream','egg','eggs','ghee','cottage cheese','whipped cream'] },
  meat:      { label: 'Meat & Fish',  icon: '🥩', keywords: ['chicken','beef','pork','lamb','turkey','duck','bacon','sausage','ham','salami','prosciutto','pancetta','salmon','tuna','shrimp','cod','tilapia','halibut','crab','lobster','scallop','scallops','anchovy','anchovies','sardine','sardines','ground beef','ground turkey','steak','ribs','brisket','tenderloin'] },
  pantry:    { label: 'Pantry',       icon: '🫙', keywords: ['flour','sugar','salt','pepper','oil','olive oil','vegetable oil','coconut oil','vinegar','soy sauce','fish sauce','hot sauce','ketchup','mustard','mayonnaise','honey','maple syrup','molasses','vanilla','baking powder','baking soda','yeast','cornstarch','breadcrumbs','pasta','rice','quinoa','oats','cereal','lentils','chickpeas','black beans','kidney beans','tomato paste','crushed tomatoes','diced tomatoes','coconut milk','broth','stock','bouillon','noodles','ramen','crackers','chips','popcorn','nuts','almonds','walnuts','pecans','peanuts','cashews','peanut butter','almond butter','jam','jelly','tahini','miso','curry','spice','spices','cumin','paprika','turmeric','cinnamon','chili','oregano','bay leaf','nutmeg','cayenne','coriander','cardamom'] },
  bakery:    { label: 'Bakery',       icon: '🍞', keywords: ['bread','sourdough','baguette','roll','rolls','bagel','bagels','pita','tortilla','tortillas','naan','croissant','muffin','muffins','cake','pie','pastry'] },
  frozen:    { label: 'Frozen',       icon: '🧊', keywords: ['frozen','ice cream','gelato','sorbet'] },
  beverages: { label: 'Beverages',    icon: '🥤', keywords: ['juice','water','soda','sparkling','wine','beer','coffee','tea','espresso','kombucha','lemonade'] },
  other:     { label: 'Other',        icon: '🛒', keywords: [] },
};

function categorize(name) {
  const lower = name.toLowerCase();
  for (const [key, cat] of Object.entries(CATEGORIES)) {
    if (key === 'other') continue;
    if (cat.keywords.some(k => lower.includes(k))) return key;
  }
  return 'other';
}

function parseInput(raw) {
  const s = raw.trim();
  const qty = s.match(/^([\d\/\s\u00bc\u00bd\u00be]+(?:\.\d+)?)\s+/);
  if (qty) {
    return { name: s.slice(qty[0].length).trim(), quantity: qty[1].trim() };
  }
  return { name: s, quantity: '' };
}

export default function GroceryList({ user }) {
  const [list, setList] = useState(null);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(true);
  const [adding, setAdding] = useState(false);
  const [showMealPlan, setShowMealPlan] = useState(false);
  const [mpWeekStart, setMpWeekStart] = useState(() => startOfWeek(new Date()));
  const [mpLoading, setMpLoading] = useState(false);
  const [mpToast, setMpToast] = useState('');
  const inputRef = useRef(null);

  useEffect(() => {
    if (user) init();
  }, [user]);

  const init = async () => {
    setLoading(true);
    try {
      const res = await apiFetch(`/groceryList/userID/${user.id || user._id}`);
      if (res.ok) {
        const data = await res.json();
        if (data.length > 0) {
          setList(data[0]);
        } else {
          // Auto-create a default list
          const cr = await apiFetch('/groceryList/', {
            method: 'POST',
            body: JSON.stringify({ name: 'My List', user_id: user.id || user._id, items: [] }),
          });
          if (cr.ok) {
            const res2 = await apiFetch(`/groceryList/userID/${user.id || user._id}`);
            if (res2.ok) {
              const d2 = await res2.json();
              setList(d2[0] || null);
            }
          }
        }
      }
    } catch (e) {}
    setLoading(false);
  };

  const addItem = async () => {
    if (!input.trim() || !list || adding) return;
    const { name, quantity } = parseInput(input);
    if (!name) return;
    setAdding(true);
    try {
      const res = await apiFetch(`/groceryList/${list._id}`, {
        method: 'PUT',
        body: JSON.stringify({ name, quantity, category: categorize(name), checked: false }),
      });
      if (res.ok) {
        setList(l => ({
          ...l,
          items: [...(l.items || []), { name, quantity, category: categorize(name), checked: false }],
        }));
        setInput('');
        inputRef.current?.focus();
      }
    } catch (e) {}
    setAdding(false);
  };

  const toggleItem = async (itemName, currentChecked) => {
    // Optimistic update
    setList(l => ({
      ...l,
      items: l.items.map(i => i.name === itemName ? { ...i, checked: !currentChecked } : i),
    }));
    try {
      await apiFetch(`/groceryList/${list._id}/${encodeURIComponent(itemName)}/check`, { method: 'PATCH' });
    } catch (e) {
      // Revert on failure
      setList(l => ({
        ...l,
        items: l.items.map(i => i.name === itemName ? { ...i, checked: currentChecked } : i),
      }));
    }
  };

  const removeItem = async (itemName) => {
    setList(l => ({ ...l, items: l.items.filter(i => i.name !== itemName) }));
    try {
      await apiFetch(`/groceryList/${list._id}/${encodeURIComponent(itemName)}`, { method: 'DELETE' });
    } catch (e) {}
  };

  const generateFromMealPlan = async () => {
    setMpLoading(true);
    const start = formatDate(mpWeekStart);
    const end = formatDate(addDays(mpWeekStart, 6));
    try {
      const res = await apiFetch('/groceryList/from-meal-plan', {
        method: 'POST',
        body: JSON.stringify({ user_id: user.id || user._id, start_date: start, end_date: end }),
      });
      if (res.ok) {
        const data = await res.json();
        if (data.added === 0) {
          setMpToast(data.message || 'No new ingredients to add.');
        } else {
          setMpToast(`Added ${data.added} ingredient${data.added !== 1 ? 's' : ''}${data.skipped ? ` (${data.skipped} already on list)` : ''}`);
          // Refresh the list
          const r2 = await apiFetch(`/groceryList/userID/${user.id || user._id}`);
          if (r2.ok) { const d2 = await r2.json(); if (d2.length) setList(d2[0]); }
        }
      }
    } catch (e) { setMpToast('Something went wrong.'); }
    setMpLoading(false);
    setTimeout(() => setMpToast(''), 4000);
  };

  const clearChecked = async () => {
    const checked = (list?.items || []).filter(i => i.checked);
    setList(l => ({ ...l, items: l.items.filter(i => !i.checked) }));
    for (const item of checked) {
      try {
        await apiFetch(`/groceryList/${list._id}/${encodeURIComponent(item.name)}`, { method: 'DELETE' });
      } catch (e) {}
    }
  };

  const items = list?.items || [];
  const checkedCount = items.filter(i => i.checked).length;
  const uncheckedCount = items.length - checkedCount;

  // Group unchecked items by category, then checked at bottom
  const grouped = {};
  for (const item of items.filter(i => !i.checked)) {
    const cat = item.category || categorize(item.name);
    if (!grouped[cat]) grouped[cat] = [];
    grouped[cat].push(item);
  }
  const catOrder = Object.keys(CATEGORIES);
  const sortedGroups = catOrder.filter(k => grouped[k]?.length > 0);

  if (!user) {
    return (
      <div className="grocery-splash">
        <div className="grocery-splash-inner">
          <h1>Your grocery list,<br />always with you.</h1>
          <p>Sign in to start building your list.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="grocery-page">
      <div className="grocery-header">
        <div className="grocery-header-left">
          <h1>Grocery List</h1>
          {!loading && items.length > 0 && (
            <span className="grocery-progress">
              {checkedCount}/{items.length}
            </span>
          )}
        </div>
        {checkedCount > 0 && (
          <button className="btn-ghost grocery-clear-btn" onClick={clearChecked}>
            Clear {checkedCount} checked
          </button>
        )}
      </div>

      {/* Meal plan generator */}
      <div className="mp-bar">
        <button
          className={`mp-toggle${showMealPlan ? ' mp-toggle--open' : ''}`}
          onClick={() => setShowMealPlan(v => !v)}
        >
          <span>📅</span> From meal plan
          <span className="mp-toggle-arrow">{showMealPlan ? '▲' : '▼'}</span>
        </button>
        {mpToast && <span className="mp-toast">{mpToast}</span>}
      </div>

      {showMealPlan && (() => {
        const end = addDays(mpWeekStart, 6);
        const sm = MONTH_NAMES[mpWeekStart.getMonth()];
        const em = MONTH_NAMES[end.getMonth()];
        const label = `${sm} ${mpWeekStart.getDate()} – ${sm !== em ? em + ' ' : ''}${end.getDate()}`;
        return (
          <div className="mp-panel">
            <div className="mp-week-nav">
              <button className="mp-nav-btn" onClick={() => setMpWeekStart(d => addDays(d, -7))}>←</button>
              <span className="mp-week-label">{label}</span>
              <button className="mp-nav-btn" onClick={() => setMpWeekStart(d => addDays(d, 7))}>→</button>
            </div>
            <p className="mp-hint">Add ingredients from all recipes planned this week.</p>
            <button className="btn-primary mp-generate-btn" onClick={generateFromMealPlan} disabled={mpLoading}>
              {mpLoading ? 'Adding…' : 'Add ingredients to list'}
            </button>
          </div>
        );
      })()}

      {/* Add input */}
      <div className="grocery-add-bar">
        <input
          ref={inputRef}
          type="text"
          className="grocery-add-input"
          placeholder='Add an item — try "2 cups flour" or just "milk"'
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && addItem()}
          disabled={loading}
        />
        <button
          className="btn-primary"
          onClick={addItem}
          disabled={adding || !input.trim() || loading}
        >
          Add
        </button>
      </div>

      {loading ? (
        <div className="grocery-loading">
          {Array.from({ length: 5 }).map((_, i) => (
            <div key={i} className="grocery-skeleton" />
          ))}
        </div>
      ) : items.length === 0 ? (
        <div className="grocery-empty">
          <p className="grocery-empty-icon">🛒</p>
          <h3>Your list is empty</h3>
          <p>Add items above to get started.</p>
        </div>
      ) : (
        <div className="grocery-content">
          {/* Unchecked items grouped by category */}
          {sortedGroups.map(catKey => {
            const cat = CATEGORIES[catKey];
            return (
              <div key={catKey} className="grocery-category">
                <div className="grocery-category-header">
                  <span className="grocery-category-icon">{cat.icon}</span>
                  <span className="grocery-category-label">{cat.label}</span>
                  <span className="grocery-category-count">{grouped[catKey].length}</span>
                </div>
                <div className="grocery-category-items">
                  {grouped[catKey].map((item, idx) => (
                    <GroceryItem
                      key={idx}
                      item={item}
                      onToggle={() => toggleItem(item.name, item.checked)}
                      onRemove={() => removeItem(item.name)}
                    />
                  ))}
                </div>
              </div>
            );
          })}

          {/* Checked items */}
          {checkedCount > 0 && (
            <div className="grocery-category grocery-category--checked">
              <div className="grocery-category-header">
                <span className="grocery-category-icon">✓</span>
                <span className="grocery-category-label">In cart</span>
                <span className="grocery-category-count">{checkedCount}</span>
              </div>
              <div className="grocery-category-items">
                {items.filter(i => i.checked).map((item, idx) => (
                  <GroceryItem
                    key={idx}
                    item={item}
                    onToggle={() => toggleItem(item.name, item.checked)}
                    onRemove={() => removeItem(item.name)}
                  />
                ))}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function GroceryItem({ item, onToggle, onRemove }) {
  return (
    <div className={`grocery-item${item.checked ? ' grocery-item--checked' : ''}`}>
      <button className="grocery-checkbox" onClick={onToggle} aria-label="Toggle">
        <span className="grocery-checkbox-inner">{item.checked ? '✓' : ''}</span>
      </button>
      <span className="grocery-item-name">{item.name}</span>
      {item.quantity && <span className="grocery-item-qty">{item.quantity}</span>}
      <button className="grocery-remove" onClick={onRemove} aria-label="Remove">✕</button>
    </div>
  );
}
